-- ============================================================================
-- SchoolAid — Multi-School Seed Script (Ticket 1.6)
-- Idempotent: safe to run multiple times (uses DELETE first).
-- Creates 2 schools with distinct configurations, teachers, and students.
-- ============================================================================

-- Clean existing data (in dependency order)
DELETE FROM attendance;
DELETE FROM student_grades;
DELETE FROM assessments;
DELETE FROM enrollments;
DELETE FROM teacher_subjects;
DELETE FROM students;
DELETE FROM teachers;
DELETE FROM classes;
DELETE FROM subjects;
DELETE FROM academic_terms;
DELETE FROM academic_sessions;
DELETE FROM profiles WHERE id NOT IN (SELECT id FROM auth.users);
DELETE FROM schools;

